code.C++:
#include <iostream>
using namespace std;
int main() {
    int choice;
    cin >> choice; // use correct operator (>>) with cin 
    switch(choice) { //fix incorrect braces/paranthesis 
        case 1:
            cout << "Option 1 selected";
            break;
        case 2:
            cout << "Option 2 selected";
            break;  // add missing break statement
        case 3:
            cout << "Option 3 selected";
            break;
        default:
            cout << "Invalid choice";
    }

    return 0;
}

